    const parsedUrl = new URL(url);

    // Check if the URL has a username and password
    if (parsedUrl.username || parsedUrl.password) {
        // If it does, create a new URL object without the username and password
        const strippedUrl = new URL(parsedUrl.origin + parsedUrl.pathname + parsedUrl.search + parsedUrl.hash);
        return strippedUrl.href;
    } else {
